";}s:8:\"requires\";s:3:\"6.2\";s:6:\"tested\";s:5:\"6.9.1\";s:12:\"requires_php\";s:3:\"7.4\";s:16:\"requires_plugins\";a:0:{}s:14:\"upgrade_notice\";s:120:\"<p>This update is an enhancement, stability, maintenance, and compatibility release. Updating is highly recommended!</p>\";}s:35:\"ultimate-blocks/ultimate-blocks.php\";O:8:\"stdClass\":13:{s:2:\"id\";s:29:\"w.org/plugins/ultimate-blocks\";s:4:\"slug\";s:15:\"ultimate-blocks\";s:6:\"plugin\";s:35:\"ultimate-blocks/ultimate-blocks.php\";s:11:\"new_version\";s:5:\"3.5.2\";s:3:\"url\";s:46:\"https://wordpress.org/plugins/ultimate-blocks/\";s:7:\"package\";s:64:\"https://downloads.wordpress.org/plugin/ultimate-blocks.3.5.2.zip\";s:5:\"icons\";a:2:{s:2:\"2x\";s:68:\"https://ps.w.org/ultimate-blocks/assets/icon-256x256.png?rev=2966061\";s:2:\"1x\";s:68:\"https://ps.w.org/ultimate-blocks/assets/icon-128x128.png?rev=2966061\";}s:7:\"banners\";a:2:{s:2:\"2x\";s:71:\"https://ps.w.org/ultimate-blocks/assets/banner-1544x500.png?rev=3439786\";s:2:\"1x\";s:70:\"https://ps.w.org/ultimate-blocks/assets/banner-772x250.png?rev=3439786\";}s:11:\"banners_rtl\";a:0:{}s:8:\"requires\";s:3:\"5.8\";s:6:\"tested\";s:5:\"6.9.1\";s:12:\"requires_php\";s:3:\"7.2\";s:16:\"requires_plugins\";a:0:{}}s:25:\"wp-members/wp-members.php\";O:8:\"stdClass\":13:{s:2:\"id\";s:24:\"w.org/plugins/wp-members\";s:4:\"slug\";s:10:\"wp-members\";s:6:\"plugin\";s:25:\"wp-members/wp-members.php\";s:11:\"new_version\";s:5:\"3.5.6\";s:3:\"url\";s:41:\"https://wordpress.org/plugins/wp-members/\";s:7:\"package\";s:59:\"https://downloads.wordpress.org/plugin/wp-members.3.5.6.zip\";s:5:\"icons\";a:2:{s:2:\"2x\";s:63:\"https://ps.w.org/wp-members/assets/icon-256x256.png?rev=1226414\";s:2:\"1x\";s:63:\"https://ps.w.org/wp-members/assets/icon-128x128.png?rev=1226414\";}s:7:\"banners\";a:1:{s:2:\"1x\";s:65:\"https://ps.w.org/wp-members/assets/banner-772x250.png?rev=1195657\";}s:11:\"banners_rtl\";a:0:{}s:8:\"requires\";s:3:\"4.0\";s:6:\"tested\";s:5:\"6.9.1\";s:12:\"requires_php\";b:0;s:16:\"requires_plugins\";a:0:{}}s:43:\"PDFEmbedder-premium/mobile_pdf_embedder.php\";O:8:\"stdClass\":23:{s:7:\"version\";s:5:\"5.3.3\";s:11:\"new_version\";s:5:\"5.3.3\";s:14:\"stable_version\";s:5:\"5.3.3\";s:8:\"external\";b:1;s:6:\"tested\";s:5:\"6.9.1\";s:8:\"requires\";s:3:\"6.1\";s:12:\"requires_php\";s:3:\"7.2\";s:15:\"active_installs\";s:6:\"300000\";s:6:\"author\";s:44:\"<a href=\"https://wp-pdf.com\">WP-PDF Team</a>\";s:14:\"author_profile\";s:39:\"https://profiles.wordpress.org/slaFFik/\";s:11:\"support_url\";s:35:\"https://wp-pdf.com/account/support/\";s:5:\"icons\";s:245:\"a:3:{s:2:\"1x\";s:61:\"https://wp-pdf.com/wp-content/uploads/2024/11/wp-pdf-icon.png\";s:2:\"2x\";s:61:\"https://wp-pdf.com/wp-content/uploads/2024/11/wp-pdf-icon.png\";s:7:\"default\";s:61:\"https://wp-pdf.com/wp-content/uploads/2024/11/wp-pdf-icon.png\";}\";s:7:\"banners\";s:202:\"a:2:{s:3:\"low\";s:79:\"https://wp-pdf.com/wp-content/uploads/2026/02/pdf-embedder-banner-772x250-1.png\";s:4:\"high\";s:80:\"https://wp-pdf.com/wp-content/uploads/2026/02/pdf-embedder-banner-1544x500-1.png\";}\";s:8:\"sections\";a:3:{s:11:\"description\";s:761:\"<p><strong>PDF Embedder Premium</strong> lets you embed PDF files beautifully and securely inside your WordPress pages and posts — with no third-party services required. Your PDFs are served directly from your own site.\n				<p>This version includes bug fixes, compatibility improvements, and enhancements based on customer feedback. Check the Changelog tab for specifics.</p><h4>What\'s included in your (Legacy) BASIC plan:</h4><ul><li>Quality-of-Lite Improvements</li><li>Search Text in PDF files</li><li>Track Views & Downloads, and more</li><li>Premium Support</li></ul><p>Need help after updating? Visit our <a href=\"https://wp-pdf.com/docs/\">documentation</a> or reach out via your <a href=\"https://wp-pdf.com/account/support/\">account dashboard</a>.</p>\";s:9:\"changelog\";s:23131:\"<h4>5.3.3 - 2026-01-29</h4>\n<ul style=\"font-weight: 400;\">\n<li>Changed: Improve the reliability of the server software detection, so we can instruct users better on how to set up Secured PDFs on their servers.</li>\n<li>Changed: Improved the rendering performance of PDF files with watermarks when they have a lot of pages.</li>\n<li>Fixed: There was an unneeded gap around PDF pages inside the PDF Viewer. We have removed the gap, so now PDF pages are flush with the edges of the Viewer.</li>\n<li>Fixed: On some mobile devices (specifically iOS devices), the scrolling of PDF files inside the PDF Viewer when opened in the fullscreen was not working correctly.</li>\n<li>Fixed: Zooming in and out using fingers while moving around the PDF file in fullscreen mode on iOS devices was not working as expected.</li>\n<li>Fixed: On mobile, double-tap to zoom in was not working correctly in fullscreen mode. To avoid crashes we disabled this behavior, but users can still use pinch-to-zoom gestures on iOS devices. Android prevents this functionality from working inside iframes.</li>\n<li>Fixed: Watermarks on top of PDF pages were disappearing when scrolling through the pages fast, especially often happening after hitting the end of the PDF document and then scrolling back up.</li>\n<li>Fixed: If the shortcode had a <code>title</code> attribute defined, the title was not set in the PDF Viewer iframe. Having the <code>iframe[title]</code> helps with accessibility.</li>\n</ul>\n<h4>5.3.2 - 2025-12-30</h4>\n<ul style=\"font-weight: 400;\">\n<li>IMPORTANT: The minimum PDF Embedder version is now v4.9.3.</li>\n<li>Changed: Compatibility with WordPress 6.9.</li>\n<li>Fixed: When a relative URL was used to embed a PDF file using a shortcode, the PDF Viewer was not rendering the file correctly.</li>\n<li>Fixed: When a relative URL was used to embed a PDF file using a shortcode, the Download button in the PDF Viewer Toolbar wasn\'t working as expected.</li>\n<li>Fixed: Fixed a potential issue with the incorrect encoding of the PDF file name if the file name contained Arabic, Chinese, and other characters. Downloaded file name should be the same as the uploaded file name.</li>\n<li>Fixed: Correctly display the time when the license key was last checked (using the site time zone).</li>\n<li>Fixed: Encrypted cached files for uploaded secured PDF files were not deleted when the associated PDF file was deleted.</li>\n<li>Fixed: Changing the zoom level was breaking our watermark rendering on top of PDF pages.</li>\n<li>Fixed: Block or shortcode option to display the watermark only on even pages was not rewriting the global plugin setting as expected.</li>\n<li>Fixed: Redefining fullpage zoom level (<code>fpzoom</code>) via shortcode or block option was not respecting user-defined values in some cases.</li>\n</ul>\n<h4>5.3.1 - 2025-04-17</h4>\n<ul>\n<li>Changed: Do not display the \"Horizontal Offset\" block option in the Watermark section of the Block Editor when \"Horizontal Alignment\" is set to \"center\".</li>\n<li>Changed: The PDF Viewer should now load up to 10% faster (depending on your theme) inside the iframes.</li>\n<li>Fixed: When editing the watermark text in our block the cursor was jumping to the end of the textarea when typing at the beginning or somewhere in the middle.</li>\n<li>Fixed: Watermark text was not rendered in the PDF Viewer when it was the same as set in the plugin\'s global options.</li>\n<li>Fixed: Potentially fix the \"home page loading in an iframe\" bug for everyone. Confirmed with at least several different cases with Thrive Theme, Thrive Architect, Paid Memberships Pro, and other plugins.</li>\n<li>Fixed: The PDF Embedder block performance was improved in the Block Editor.</li>\n<li>Fixed: Decrease the chances of unneeded server redirects when accessing the secured PDF file - this improves the overall PDF Viewer speed as less time is spent retrieving the file from the server.</li>\n<li>Fixed: PDF files were not rendered in the PDF Viewer when the WordPress installation was in a domain subdirectory.</li>\n<li>Fixed: Compatibility with other plugins was significantly improved. This should greatly decrease the chances of a home page being loaded inside the PDF Viewer.</li>\n</ul>\n<h4>5.3.0 - 2025-01-22</h4>\n<ul>\n<li>IMPORTANT: The minimum PHP version is now PHP v7.2.</li>\n<li>IMPORTANT: The minimum WordPress version is now v6.1.</li>\n<li>IMPORTANT: The minimum PDF Embedder version is now v4.9.0.</li>\n<li>Added: Block the interaction with the toolbar when a mobile device is used to view the PDF file, so users won\'t be able to navigate pages and change the zoom until they click the \"View in full screen\" button.</li>\n<li>Added: In the Block Editor there is now a handy link to check the selected PDF file tracking data (views and downloads). Check the Actions section for the PDF Embedder block.</li>\n<li>Changed: Changed: Compatibility with WordPress 6.7.</li>\n<li>Changed: The sharpness and quality of the text in the PDF Viewer were significantly improved.</li>\n<li>Changed: Further improvements to the PDF Embedder block in the Block Editor.</li>\n<li>Fixed: The main JavaScript file used to render the PDF Viewer was not correctly registered in WordPress. In the past, this required customers to manually clear the browser cache after each plugin upgrade.</li>\n<li>Fixed: Fullscreen mode was triggering incorrectly in cases where several embedded PDF files were not coming from the WordPress Media library.</li>\n<li>Fixed: The height of the PDF Viewer, embedded on a page, was fixed at 1000px by default. Now it tries to fluidly change depending on each page of the PDF document height unless you set the height other than to the <code>max</code> value.</li>\n<li>Fixed: There were excessive gaps at the top/bottom of the PDF Viewer when the toolbar was set to be displayed on hover.</li>\n<li>Fixed: Some PDF files were rendered with decreased quality.</li>\n<li>Fixed: We fixed compatibility with the Paid Memberships Pro - Member Homepages Add On, so you should see the PDF files embedded into the member\'s homepage.</li>\n<li>Fixed: Pressing <code>cmd+s</code> or <code>ctrl+s</code> on the keyboard was always triggering the download of the PDF file, now it\'s connected to whether the download button is enabled or not.</li>\n</ul>\n<h4>5.2.3 - 2024-06-12</h4>\n<ul>\n<li>Fixed: There was a small typo in the code that generated in certain cases an incorrect URL to download PDF files.</li>\n<li>Fixed: Sometimes the PDF Viewer was still blocked by the \"View in full screen\" button on mobile devices.</li>\n<li>Fixed: Remove some debugging messages that are displayed in the browser console in certain cases by the PDF.js library.</li>\n</ul>\n<h4>5.2.2 - 2024-06-07</h4>\n<ul>\n<li>Fixed: Remove debug code that was left in the plugin by mistake resulting in fatal error.</li>\n</ul>\n<h4>5.2.1 - 2024-06-07</h4>\n<ul>\n<li>Changed: Do not display the license key on the About page in plain text.</li>\n<li>Fixed: There was an error in code that prevented WordPress from removing the plugin using the plugins admin interface.</li>\n<li>Fixed: PDF files located outside the default WordPress uploaded Media files location were not rendered in the Viewer, home page was loaded instead.</li>\n</ul>\n<h4>5.2.0 - 2024-06-06</h4>\n<ul>\n<li>IMPORTANT: The minimum WordPress version is now WordPress v5.8.</li>\n<li>IMPORTANT: The minimum PHP version is now PHP v7.0.</li>\n<li>IMPORTANT: If you are using a caching plugin and added PDF Embedder JS files to the exclusion list, you will need to do that again due to changed JS file names.</li>\n<li>Added: A ton of new configuration options were added to the PDF Embedder block. If modified, they override the global plugin settings on a per-file basis.</li>\n<li>Changed: The plugin admin area interface has been refreshed.</li>\n<li>Changed: The plugin has been tested with the latest version of WordPress.</li>\n<li>Changed: Block was rewritten from scratch, and now it looks and works better in the Block Editor and also syncs its default settings with plugin options.</li>\n<li>Changed: The PDF Viewer (which continues to use an iframe) now has a proper canonical URL when pointing to the public PDF file. Secured PDFs have a robots <code>noindex</code> meta tag.</li>\n<li>Fixed: A lot of strings in the plugin have been fixed to make them accurate and translatable.</li>\n<li>Fixed: Several security-related improvements have been implemented (data sanitization and escaping). Also, improved the way PDF files are rendered to prevent arbitrary script execution.</li>\n<li>Fixed: PDF file embedded via a shortcode was not loadable when the content was retrieved via AJAX.</li>\n<li>Fixed: Text in PDF files in certain languages (like Japanese and Korean) was not rendered correctly.</li>\n<li>Fixed: Download and View counter can be enabled and disabled on a per PDF file basis via shortcode attributes (<code>view_counter</code> and <code>download_counter</code>) or block options (toggle to on/off).</li>\n<li>Fixed: Toolbar locations <code>bottom</code> and <code>both</code> were not working properly due to various JavaScript errors.</li>\n<li>Fixed: There was incorrect padding at the top of the viewer when the toolbar location was set to other than <code>top</code> or <code>both</code>.</li>\n<li>Fixed: The <code>zoom</code> attribute defined for a specific file was not passed properly to the viewer.</li>\n<li>Fixed: User-redefined zoom value was not preselected inside the Viewer Toolbar.</li>\n<li>Fixed: External links option (global for the plugin and per individual PDF file) was not respecting the \"Open in new tab\" setting.</li>\n<li>Fixed: The fullscreen button in the viewer was not working correctly. You can now close it by pressing the <code>ESC</code> key on your keyboard or clicking the same fullscreen icon again.</li>\n<li>Fixed: PDF Attachment pages were having some performance issues due to the excessive number of database queries.</li>\n<li>Fixed: Improved the responsiveness (ability to interact with) of scrollbars and automatically hidden toolbar when it\'s not fixed.</li>\n<li>Fixed: Improved the readability of the text inside the Search panel inside the Viewer.</li>\n<li>Fixed: You can now again set the first page of the multipage PDF file to be displayed by default via a shortcode attribute or a block option.</li>\n<li>Fixed: The \"Scroll to Top\" attribute in the shortcode (or plugin global setting) was not scrolling to the top of the PDF file when arrow navigation within the Viewer was used.</li>\n<li>Fixed: Watermarks are now part of the Viewer canvas which makes them more reliable.</li>\n<li>Fixed: Correctly handle newline characters in the watermark text, they are now preserved.</li>\n<li>Fixed: Correctly center the watermark text in the PDF Viewer according to the viewer sizes.</li>\n<li>Fixed: The loading speed of PDF files improved in various cases.</li>\n<li>Fixed: It was not possible to download the PDF file from within the Viewer on certain WordPress installations.</li>\n<li>Fixed: Some performance-related issues were addressed, so the plugin has less effect on the overall site performance.</li>\n<li>Fixed: PDF files\' encryption was not working as expected.</li>\n<li>Fixed: Several encoding issues in various PDF files were fixed.</li>\n<li>Fixed: \"Disable right-click\" option was not working properly.</li>\n<li>Fixed: Enabling the tracking functionality (PDF views and downloads) didn\'t have an effect, now the counters are displayed and incremented properly.</li>\n<li>Fixed: The mobile options in the plugin were not working as expected, now the button to display the file in full screen is visible on mobile devices, threshold is configurable. The threshold is applicable to the PDF Viewer width.</li>\n<li>Fixed: PDF Viewer styles on mobile are improved a little bit. More to come!</li>\n</ul>\n<h4>5.1.4</h4>\n<ul>\n<li>Fix: Clicking PDF links not opening.</li>\n<li>Fix: Toolbar defaults not being respected.</li>\n<li>Fix: Some characters not displaying in PDFs.</li>\n</ul>\n<h4>5.1.3</h4>\n<ul>\n<li>Fix: Prevent plugins from injecting content into the PDF frame.</li>\n</ul>\n<h4>5.1.2</h4>\n<ul>\n<li>Fix: Theme Conflicts preventing PDF loading.</li>\n<li>Fix: Theme styling conflict.</li>\n<li>Fix: PDF scaling incorrectly.</li>\n<li>Fix: Cases that removed the admin bar.</li>\n</ul>\n<h4>5.1.1</h4>\n<ul>\n<li>Added: PDF Text Search.</li>\n<li>Added: Upgrade the pdfjs library version.</li>\n</ul>\n<h4>5.0.2</h4>\n<ul>\n<li>Hotfix: wrong extract folder name fix added.</li>\n</ul>\n<h4>5.0.1</h4>\n<ul>\n<li>Roll back scripts</li>\n</ul>\n<h4>5.0.0</h4>\n<ul>\n<li>Update scripts for new features</li>\n</ul>\n<h4>4.4.3</h4>\n<ul>\n<li>Wrong extract folder name fix added</li>\n</ul>\n<h4>4.4.2</h4>\n<ul>\n<li>Added support for the Italian language</li>\n<li>Added compatibility for WordPress 5.7</li>\n</ul>\n<h4>4.4.1</h4>\n<ul>\n<li>Fix language compatibility issue in the viewer</li>\n<li>Fixes JS and CSS files cache issue</li>\n<li>Added compatibility for WordPress 5.3.2</li>\n</ul>\n<h4>4.4</h4>\n<ul>\n<li>Added compatibility for WordPress 5.3</li>\n<li>Fixes multiple PDF rendering issues in the viewer (i.e. jumping pages, etc.)</li>\n</ul>\n<h4>4.3</h4>\n<ul>\n<li>Fixed Scrollbar issues with Firefox and iOS devices. Improved compatibility</li>\n</ul>\n<h4>4.2</h4>\n<ul>\n<li>Fixed script problems on some Gutenberg editor installations. Improved compatibility</li>\n</ul>\n<h4>4.1</h4>\n<ul>\n<li>Added compatibility for WordPress 5.2.1</li>\n<li>Fixed CSS problems for Mac Devices</li>\n</ul>\n<h4>4.0</h4>\n<ul>\n<li>Added compatibility for WordPress 5.0</li>\n</ul>\n<h4>3.2</h4>\n<ul>\n<li>Added Compatibility for Gutenberg Editor</li>\n</ul>\n<h4>3.1.8</h4>\n<ul>\n<li>Updated to use the latest rendering library pdf.js. Fixes some \'strange character\' issues amongst other improvements.</li>\n<li>No longer needs a standalone compatbility.js file so this is not loaded in your site anymore.</li>\n<li>Translation files added for HU locale.</li>\n</ul>\n<h4>3.1.6</h4>\n<ul>\n<li>Recalculates fresh viewer size more often in response to resize events. Previous versions attempted to increase performance by only recalculating viewer size when it had changed, but this missed some required resizing after Javascript-based tabs were clicked.</li>\n</ul>\n<h4>3.1.5</h4>\n<ul>\n<li>Fixed some issues with the zoom appearance.</li>\n<li>In full-screen mode, when continuous page scrolling is off, now jumps to the start of a page when next/prev is clicked.</li>\n</ul>\n<h4>3.1.4</h4>\n<ul>\n<li>The mouse scroll wheel is now more consistent across all browsers (in terms of scroll speed).</li>\n<li>No longer jumps to the start of the doc on window resize.</li>\n<li>The view in the Full Screen button no longer scrolls underneath the large button.</li>\n<li>When scrollbars are always visible, they no longer cut off the edge of the PDF underneath.</li>\n</ul>\n<h4>3.1.2</h4>\n<ul>\n<li>Updated for compatibility with the upcoming WordPress 4.8 release.</li>\n<li>The new mouse wheel fix for Firefox wasn\'t working with some themes.</li>\n</ul>\n<h4>3.1.1</h4>\n<ul>\n<li>Updated to the latest version of pdf.js, the underlying library which is used to render the PDFs.</li>\n<li>Fix for mouse wheel issue on Firefox - window was sometimes scrolling when only the document was supposed to.</li>\n<li>Minor CSS additions to prevent conflicts with a particular theme.</li>\n</ul>\n<h4>3.0.1</h4>\n<ul>\n<li>PLEASE NOTE PAGE TURNERS have been removed from the plugin - the large left/right arrows that can appear at the edge of the PDF on mouse hover. They are considered redundant now continuous page scrolling is available (see below).</li>\n<li>Continuous page scrolling. Use the mouse or touch to scroll straight onto the next page without having to click the next/prev buttons anymore.</li>\n<li>Option to switch off the new \'Continous Page Scrolling\' feature so the user has to click the next/prev buttons to change pages as in previous versions.</li>\n<li>Options to add vertical and/or horizontal scrollbars. Shortcode version is <code><code>scrollbar=\'vertical\'</code></code>, <code>\'horizontal\'</code>, <code>\'both\'</code>, or <code>\'none\'</code>. Default is <code>none</code>.</li>\n<li>Fix to tidy up the HTML generated by the plugin which was being removed by the W3 Total Cache plugin leading to functionality being restricted.</li>\n<li>Scrolling by touch or mouse will now defer to the browser when at the very top or bottom of the PDF. This means that when you already scrolled to the very bottom of the PDF, further scrolling will cause the whole web page to scroll down instead of nothing happening. Previously, it was sometimes difficult to navigate to the section of the web page below the embedded PDF.</li>\n<li>The plugin now respects the <code>SCRIPT_DEBUG</code> flag in the <code>wp-config.php</code> file and displays non-minified versions of the JS files if this is set to true. Helps debug any issues.</li>\n<li>No longer displays \'opt-in to beta updates\' to new installs.</li>\n<li>Added NL language.</li>\n</ul>\n<h4>2.9.2</h4>\n<ul>\n<li>You can now opt-in to receive early beta releases of the plugin - change this setting in the License tab of the plugin settings.</li>\n<li>Multisite enhancements - it is now possible to either Network Activate the plugin (recommended) or allow individual sub-sites to Activate on a per-site basis. This was always possible, but the plugin settings could not be accessed in per-site mode. It may still be necessary to set the license on the Network admin version of the plugin settings, so you would try network activating to set the license key only, then revert to per-site activation if desired.</li>\n</ul>\n<h4>2.8</h4>\n<ul>\n<li>\'Page Turner\' arrows appear when hovering over the left/right edges of the PDF for easier navigation. This can be turned off in settings or by individual shortcodes.</li>\n<li>Toolbar position now has an option \'No Toolbar\' to completely remove the toolbar (and presumably rely on the new page-turners for page navigation).</li>\n</ul>\n<h4>2.7.5</h4>\n<ul>\n<li>Fixed display (and touch screen zoom) on high-resolution screens under certain browsers/devices.</li>\n<li>The latest ZIP is now available through a link in the License tab, so it can be obtained in cases where the automatic update fails on the Plugins page.</li>\n</ul>\n<h4>2.7.3</h4>\n<ul>\n<li>Tested up to WordPress 4.6.</li>\n<li>Title parameter only inserted into shortcode if needed, to keep things tidy.</li>\n<li>Added filter <code>my_pdfemb_override_send_to_editor</code> so you can turn off the shortcode generation.</li>\n</ul>\n<h4>2.7</h4>\n<ul>\n<li>Improved support for high-resolution displays (retina).</li>\n<li>Reduced \'flicker\' when moving around documents on mobiles.</li>\n<li>Uses the latest version of the pdf.js library for rendering PDFs.</li>\n<li>Improvements to help with SEO ranking through embedded PDFs: the PDF embed initially appears as a link to the PDF file, through the link text provided in a new \'title\' shortcode parameter (or the base filename if no \'title\' is specified). This should be visible to search engine crawlers, and also to viewers in the case of Javascript failure or delay.</li>\n<li>Toolbar buttons have an <code>type=\"button\"</code> attribute to avoid conflicts with some other plugins.</li>\n<li>Spanish translation contributed by Armando Landois.</li>\n<li>pdfemb_filter_shortcode_attrs filter so developers can change default shortcode parameters through code.</li>\n</ul>\n<h4>2.5.5</h4>\n<ul>\n<li>Added keyboard shortcuts in fullscreen mode. Cursor keys to move about the current page, +/- to zoom in/out, Page Up or Page Down to move to the next/prev page (Use Fn + Down/Up Arrow on a Mac).</li>\n<li>New <code>zoom=\"x\"</code> shortcode parameter to start display on a specified zoom percentage.</li>\n<li>Fix for Right-to-Left languages.</li>\n</ul>\n<h4>2.5.4</h4>\n<ul>\n<li>Added French translation.</li>\n<li>Confirmed to work with WP4.5 including resolving a layout conflict with the new Twentysixteen theme.</li>\n</ul>\n<h4>2.5.3</h4>\n<ul>\n<li>New shortcode parameter: <code>pagetextbox=\"on\"</code> to ensure the \'page number\' text box is always visible for the user to enter a page number to jump to. If omitted or \"off\", the user needs to click on the page number display for it to change into a text box, as before.</li>\n</ul>\n<h4>2.5.1</h4>\n<ul>\n<li>Displays error message if the user attempts to Activate when the free version of the plugin is already Active.</li>\n</ul>\n<h4>2.5</h4>\n<ul>\n<li>Uses the latest version of underlying pdf.js technology to render PDFs.</li>\n<li>New option \'Scroll to top of the page when user clicks next/prev\'.</li>\n<li>\'Attachment Pages\' for PDFs now use the PDF Embedder viewer to display them - WordPress default is just a link to the PDF file.</li>\n</ul>\n<h4>2.4.7</h4>\n<ul>\n<li>Some settings were difficult to change under a WordPress multisite install.</li>\n</ul>\n<h4>2.4.4</h4>\n<ul>\n<li>Hyperlinks are fixed for certain mobile devices.</li>\n<li>New option to improve mobile zooming on some sites.</li>\n</ul>\n<h4>2.4.3</h4>\n<ul>\n<li>Option in Settings to open hyperlinks in new tab/window - can be overridden in shortcode using <code>newwindow=\"on|off\"</code>.</li>\n<li>Now supports internal hyperlinks.</li>\n</ul>\n<h4>2.4.1</h4>\n<ul>\n<li>Track the number of views and downloads - displays next to the PDF\'s other info in the Media Library.</li>\n</ul>\n<h4>2.4</h4>\n<ul>\n<li>Hyperlinks are now supported - both internal within PDF and external to other web pages.</li>\n<li>Jump straight to page number by clicking on Page and typing the number.</li>\n<li>The new shortcode parameter <code>page=\"x\"</code> opens up a document on a specified page number.</li>\n<li>Translation-ready! Please contribute your translations.</li>\n<li>Compatibility with WordPress 4.4.</li>\n</ul>\n<h4>2.2.5</h4>\n<ul>\n<li>Better explanation of some error messages (e.g. attempt to access PDF on a different domain).</li>\n<li>Forced white background by default - some Theme\'s CSS would override.</li>\n</ul>\n<h4>2.2.4</h4>\n<ul>\n<li>Option to add \'Download PDF\' button to toolbar.</li>\n</ul>\n<h4>2.2.3</h4>\n<ul>\n<li>No longer complains of invalid license in some cases where it shouldn\'t.</li>\n</ul>\n<h4>2.2.2</h4>\n<ul>\n<li>Redesigned toolbar buttons</li>\n</ul>\n<h4>2.2</h4>\n<ul>\n<li>The new version of PDF.js fixes some PDF rendering bugs.</li>\n</ul>\n<h4>2.1.7</h4>\n<ul>\n<li>Fixed a bug with full-screen height calculation which left the toolbar invisible in full-screen mode.</li>\n</ul>\n<h4>2.1.6</h4>\n<ul>\n<li>Height can be specified in global Settings -&gt; PDF Embedder and pulls through correctly as a default in any shortcode that doesn\'t already have its height specified.</li>\n</ul>\n<h4>2.1.4</h4>\n<ul>\n<li>Obtains PDF over same transport (https/http) as host page, regardless of that specified in the shortcode url parameter. This avoids conflicts and failure to display PDF if the two don\'t match.</li>\n</ul>\n<h4>2.1.3</h4>\n<ul>\n<li>Fixes to workaround iPhone Safari bugs.</li>\n</ul>\n<h4>2.1.1</h4>\n<ul>\n<li>ESC to exit full-screen mode. Automatic plugin updates. Settings now contain site-wide defaults for appearance (width/toolbar) - and can be overridden by shortcodes.</li>\n</ul>\n\";s:3:\"faq\";s:1248:\"<h4>Will updating break my existing embedded PDFs?</h4>\n<p>No. Your existing PDF embeds will continue to work exactly as before. We maintain backward compatibility with all shortcodes and block settings.</p>\n<h4>Do I need to do anything after updating?</h4>\n<p>Just click Update and you\'re done. If you use a caching plugin (like WP Rocket, W3 Total Cache, etc.), clear your cache after updating so your visitors get the latest version of the viewer.</p>\n<h4>Will this update affect my license or billing?</h4>\n<p>No. Updates are included with your active license and won\'t affect your subscription in any way.</p>\n<h4>Something broke after updating - what should I do?</h4>\nFirst, try clearing your site cache. If the issue persists, deactivate and reactivate the plugin. Still not working? Contact us at wp-pdf.com/support and we\'ll get it sorted quickly.</p>\n<h4>Can I roll back to the previous version if needed?</h4>\n<p>Yes. You can use a plugin like WP Rollback to revert to a previous version if you need to, though we recommend reaching out to support first so we can fix the root cause.</p>\n<h4>Is my data safe during the update?</h4>\n<p>Yes. Plugin updates never touch your uploaded PDF files, your settings, or your database content.</p>\";}s:7:\"package\";s:0:\"\";s:13:\"download_link\";s:0:\"\";s:4:\"slug\";s:20:\"pdf-embedder-premium\";s:4:\"name\";s:20:\"PDF Embedder Premium\";s:3:\"url\";s:18:\"https://wp-pdf.com\";s:8:\"homepage\";s:27:\"https://wp-pdf.com/account/\";s:12:\"last_updated\";N;s:2:\"id\";i:287;s:6:\"plugin\";s:43:\"PDFEmbedder-premium/mobile_pdf_embedder.php\";}}s:12:\"translations\";a:2:{i:0;a:7:{s:4:\"type\";s:6:\"plugin\";s:4:\"slug\";s:11:\"hello-dolly\";s:8:\"language\";s:5:\"de_DE\";s:7:\"version\";s:5:\"1.7.2\";s:7:\"updated\";s:19:\"2026-02-27 16:54:17\";s:7:\"package\";s:78:\"https://downloads.wordpress.org/translation/plugin/hello-dolly/1.7.2/de_DE.zip\";s:10:\"autoupdate\";b:1;}i:1;a:7:{s:4:\"type\";s:6:\"plugin\";s:4:\"slug\";s:10:\"wp-members\";s:8:\"language\";s:5:\"de_DE\";s:7:\"version\";s:7:\"3.5.5.1\";s:7:\"updated\";s:19:\"2026-02-26 18:44:31\";s:7:\"package\";s:79:\"https://downloads.wordpress.org/translation/plugin/wp-members/3.5.5.1/de_DE.zip\";s:10:\"autoupdate\";b:1;}}s:9:\"no_update\";a:9:{s:19:\"akismet/akismet.php\";O:8:\"stdClass\":10:{s:2:\"id\";s:21:\"w.org/plugins/akismet\";s:4:\"slug\";s:7:\"akismet\";s:6:\"plugin\";s:19:\"akismet/akismet.php\";s:11:\"new_version\";s:3:\"5.6\";s:3:\"url\";s:38:\"https://wordpress.org/plugins/akismet/\";s:7:\"package\";s:54:\"https://downloads.wordpress.org/plugin/akismet.5.6.zip\";s:5:\"icons\";a:2:{s:2:\"2x\";s:60:\"https://ps.w.org/akismet/assets/icon-256x256.png?rev=2818463\";s:2:\"1x\";s:60:\"https://ps.w.org/akismet/assets/icon-128x128.png?rev=2818463\";}s:7:\"banners\";a:2:{s:2:\"2x\";s:63:\"https://ps.w.org/akismet/assets/banner-1544x500.png?rev=2900731\";s:2:\"1x\";s:62:\"https://ps.w.org/akismet/assets/banner-772x250.png?rev=2900731\";}s:11:\"banners_rtl\";a:0:{}s:8:\"requires\";s:3:\"5.8\";}s:33:\"classic-editor/classic-editor.php\";O:8:\"stdClass\":10:{s:2:\"id\";s:28:\"w.org/plugins/classic-editor\";s:4:\"slug\";s:14:\"classic-editor\";s:6:\"plugin\";s:33:\"classic-editor/classic-editor.php\";s:11:\"new_version\";s:5:\"1.6.7\";s:3:\"url\";s:45:\"https://wordpress.org/plugins/classic-editor/\";s:7:\"package\";s:63:\"https://downloads.wordpress.org/plugin/classic-editor.1.6.7.zip\";s:5:\"icons\";a:2:{s:2:\"2x\";s:67:\"https://ps.w.org/classic-editor/assets/icon-256x256.png?rev=1998671\";s:2:\"1x\";s:67:\"https://ps.w.org/classic-editor/assets/icon-128x128.png?rev=1998671\";}s:7:\"banners\";a:2:{s:2:\"2x\";s:70:\"https://ps.w.org/classic-editor/assets/banner-1544x500.png?rev=1998671\";s:2:\"1x\";s:69:\"https://ps.w.org/classic-editor/assets/banner-772x250.png?rev=1998676\";}s:11:\"banners_rtl\";a:0:{}s:8:\"requires\";s:3:\"4.9\";}s:21:\"hello-dolly/hello.php\";O:8:\"stdClass\":10:{s:2:\"id\";s:25:\"w.org/plugins/hello-dolly\";s:4:\"slug\";s:11:\"hello-dolly\";s:6:\"plugin\";s:21:\"hello-dolly/hello.php\";s:11:\"new_version\";s:5:\"1.7.2\";s:3:\"url\";s:42:\"https://wordpress.org/plugins/hello-dolly/\";s:7:\"package\";s:60:\"https://downloads.wordpress.org/plugin/hello-dolly.1.7.2.zip\";s:5:\"icons\";a:2:{s:2:\"2x\";s:64:\"https://ps.w.org/hello-dolly/assets/icon-256x256.jpg?rev=2052855\";s:2:\"1x\";s:64:\"https://ps.w.org/hello-dolly/assets/icon-128x128.jpg?rev=2052855\";}s:7:\"