(1491, 1, '2025-12-19 14:09:51', '2025-12-19 13:09:51', '/* ===== SCHRIFTART ===== */\n@import url(\'https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700&display=swap\');\n\nbody,\nbutton,\ninput,\nselect,\ntextarea,\nh1, h2, h3, h4, h5, h6,\n.site-title,\n.entry-title,\n.widget-title {\n    font-family: \'Inter\', -apple-system, BlinkMacSystemFont, sans-serif !important;\n}\n\n/* ===== FOOTER AUSBLENDEN ===== */\n.site-footer {\n    display: none !important;\n}', 'twentyfifteen', '', 'publish', 'closed', 'closed', '', 'twentyfifteen', '', '', '2025-12-19 14:11:13', '2025-12-19 13:11:13', '', 0, 'https://www.msvwilen.ch/2025/12/19/twentyfifteen/', 0, 'custom_css', '', 0),
(1492, 1, '2025-12-19 14:09:51', '2025-12-19 13:09:51', '/* ===== SCHRIFTART ===== */\n@import url(\'https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700&display=swap\');\n\nbody,\nbutton,\ninput,\nselect,\ntextarea,\nh1, h2, h3, h4, h5, h6,\n.site-title,\n.entry-title,\n.widget-title {\n    font-family: \'Inter\', -apple-system, BlinkMacSystemFont, sans-serif !important;\n}\n\n/* ===== KOMPAKTERE ABSTÄNDE ===== */\n\n/* Abstand zwischen Beiträgen */\n.hentry {\n    padding-top: 4% !important;\n    padding-bottom: 4% !important;\n}\n\n/* ===== MAIN CONTENT OBEN AUSRICHTEN ===== */\n.site-content {\n    padding-top: 8.5% !important;\n    margin-top: 0 !important;\n}\n\n.site-main {\n    padding-top: 0 !important;\n    margin-top: 0 !important;\n}\n\n.hentry:first-child {\n    padding-top: 0 !important;\n}\n\n.page-header,\n.entry-header {\n    padding-top: 0 !important;\n    margin-top: 0 !important;\n}\n/* Sidebar kompakter */\n.site-header {\n    padding: 5% !important;\n}\n\n/* Widget-Abstände */\n.widget {\n    margin-bottom: 20px !important;\n}\n\n/* Abstand unter Überschriften */\n.entry-title {\n    margin-bottom: 0.5em !important;\n}\n\n/* Abstand nach Beitragsmeta (Datum etc.) */\n.entry-header {\n    margin-bottom: 1em !important;\n}\n\n/* Footer kompakter */\n.site-footer {\n    padding: 2% 0 !important;\n}\n\n/* Abstand zwischen Absätzen im Text */\n.entry-content p {\n    margin-bottom: 1em !important;\n}\n\n/* Seiteninhalt (Pages) kompakter */\n.page .entry-content {\n    padding-top: 0 !important;\n}', 'twentyfifteen', '', 'inherit', 'closed', 'closed', '', '1491-revision-v1', '', '', '2025-12-19 14:09:51', '2025-12-19 13:09:51', '', 1491, 'https://www.msvwilen.ch/?p=1492', 0, 'revision', '', 0),
(1494, 1, '2025-12-19 14:10:11', '2025-12-19 13:10:11', '/* ===== SCHRIFTART ===== */\n@import url(\'https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700&display=swap\');\n\nbody,\nbutton,\ninput,\nselect,\ntextarea,\nh1, h2, h3, h4, h5, h6,\n.site-title,\n.entry-title,\n.widget-title {\n    font-family: \'Inter\', -apple-system, BlinkMacSystemFont, sans-serif !important;\n}', 'twentyfifteen', '', 'inherit', 'closed', 'closed', '', '1491-revision-v1', '', '', '2025-12-19 14:10:11', '2025-12-19 13:10:11', '', 1491, 'https://www.msvwilen.ch/?p=1494', 0, 'revision', '', 0);
